inline:<div id="header-root">
  <style>
    #header-root { background: #0A0A12; color: #00F2FF; padding: 120px 16px; display: flex; flex-direction: column; align-items: center; font-family: 'Montserrat', sans-serif; }
    .c1-brand { font-size: 4rem; font-weight: 900; color: #FF00E5; letter-spacing: 0.5rem; margin: 0; }
    .c1-sub { font-family: 'JetBrains Mono', monospace; color: #00F2FF; margin-top: 16px; }
    .c1-visual { width: 300px; height: 100px; border: 2px solid #00F2FF; position: relative; margin-top: 40px; overflow: hidden; }
    .c1-helix-static { width: 100%; height: 100%; background: repeating-linear-gradient(45deg, transparent, transparent 10px, #FF00E5 10px, #FF00E5 11px); }
  </style>
  <h1 class="c1-brand">DNA 2026</h1>
  <p class="c1-sub">Interactive Workshop: The Molecular Architecture</p>
  <div class="c1-visual" id="header-root-visual">
    <div class="c1-helix-static"></div>
  </div>
  <script>
    window.c1_mount = () => {
      if (window.matchMedia('(prefers-reduced-motion: reduce)').matches) return;
      const el = document.getElementById('header-root-visual');
      el.style.transition = 'transform 2s ease-in-out';
      el.style.transform = 'scale(1.05)';
    };
    window.c1_initializeHeaderAnimation = () => {};
    window.c1_destroy = () => {};
  </script>
</div>
